# SAML namespace constants
NAMESPACES = {
    'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
    'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
    'ds': 'http://www.w3.org/2000/09/xmldsig#'
}

# Configuration
SP_CONFIG = {
    'entity_id': 'http://localhost:5000/saml/metadata',
    'acs_url': 'http://localhost:5000/saml/acs',
    'slo_url': 'http://localhost:5000/saml/slo'
}

IDP_CONFIG = {
    'entity_id': 'http://idp.example.com/saml/metadata',
    'sso_url': 'http://idp.example.com/saml/sso',
    'slo_url': 'http://idp.example.com/saml/slo'
}


def parse_saml_response(saml_response_b64):
    """Parse SAML response and extract assertion data"""
    try:
        saml_response_xml = base64.b64decode(saml_response_b64)
        root = ET.fromstring(saml_response_xml)
        
        # Find Status element
        status = root.find('.//samlp:Status/samlp:StatusCode', NAMESPACES)
        if status is None or status.get('Value') != 'urn:oasis:names:tc:SAML:2.0:status:Success':
            return None, 'SAML Response status is not Success'
        
        # Find Assertion
        assertion = root.find('.//saml:Assertion', NAMESPACES)
        if assertion is None:
            return None, 'No Assertion found in SAML Response'
        
        return assertion, None
    except Exception as e:
        return None, f'Error parsing SAML response: {str(e)}'


def extract_user_attributes(assertion):
    """Extract user attributes from SAML assertion"""
    user_data = {}
    
    # Extract NameID (usually the username or email)
    name_id = assertion.find('.//saml:Subject/saml:NameID', NAMESPACES)
    if name_id is not None:
        user_data['name_id'] = name_id.text
        user_data['name_id_format'] = name_id.get('Format', '')
    
    # Extract attributes
    attributes = {}
    attribute_statements = assertion.findall('.//saml:AttributeStatement/saml:Attribute', NAMESPACES)
    
    for attr in attribute_statements:
        attr_name = attr.get('Name')
        attr_friendly_name = attr.get('FriendlyName', attr_name)
        
        # Get attribute values
        attr_values = []
        for attr_value in attr.findall('saml:AttributeValue', NAMESPACES):
            if attr_value.text:
                attr_values.append(attr_value.text)
        
        if len(attr_values) == 1:
            attributes[attr_friendly_name] = attr_values[0]
        else:
            attributes[attr_friendly_name] = attr_values
    
    user_data['attributes'] = attributes
    
    # Extract conditions
    conditions = assertion.find('.//saml:Conditions', NAMESPACES)
    if conditions is not None:
        user_data['not_before'] = conditions.get('NotBefore')
        user_data['not_on_or_after'] = conditions.get('NotOnOrAfter')
    
    # Extract AuthnStatement
    authn_statement = assertion.find('.//saml:AuthnStatement', NAMESPACES)
    if authn_statement is not None:
        user_data['authn_instant'] = authn_statement.get('AuthnInstant')
        user_data['session_index'] = authn_statement.get('SessionIndex')
        
        authn_context = authn_statement.find('.//saml:AuthnContext/saml:AuthnContextClassRef', NAMESPACES)
        if authn_context is not None:
            user_data['authn_context'] = authn_context.text
    
    return user_data


def validate_assertion(assertion):
    """Validate SAML assertion"""
    errors = []
    
    # Check if assertion exists
    if assertion is None:
        errors.append('Assertion is missing')
        return False, errors
    
    # Validate conditions
    conditions = assertion.find('.//saml:Conditions', NAMESPACES)
    if conditions is not None:
        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')
        
        current_time = datetime.utcnow()
        
        if not_before:
            not_before_time = datetime.fromisoformat(not_before.replace('Z', '+00:00'))
            if current_time < not_before_time.replace(tzinfo=None):
                errors.append('Assertion is not yet valid (NotBefore condition)')
        
        if not_on_or_after:
            not_on_or_after_time = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00'))
            if current_time >= not_on_or_after_time.replace(tzinfo=None):
                errors.append('Assertion has expired (NotOnOrAfter condition)')
        
        # Validate audience restriction
        audience = conditions.find('.//saml:AudienceRestriction/saml:Audience', NAMESPACES)
        if audience is not None and audience.text != SP_CONFIG['entity_id']:
            errors.append(f'Audience restriction failed. Expected {SP_CONFIG["entity_id"]}, got {audience.text}')
    
    # Check for Subject
    subject = assertion.find('.//saml:Subject', NAMESPACES)
    if subject is None:
        errors.append('Subject is missing from assertion')
    
    return len(errors) == 0, errors


def create_user_session(user_data):
    """Create a user session from extracted SAML data"""
    session.clear()
    session['authenticated'] = True
    session['name_id'] = user_data.get('name_id')
    session['session_index'] = user_data.get('session_index')
    session['attributes'] = user_data.get('attributes', {})
    session['authn_instant'] = user_data.get('authn_instant')
    session['login_time'] = datetime.utcnow().isoformat()
    
    # Set session timeout
    session.permanent = True
    app.permanent_session_lifetime = timedelta(hours=8)


def generate_authn_request():
    """Generate SAML AuthnRequest"""
    request_id = f"_id_{secrets.token_hex(16)}"
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    authn_request = f'''<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{IDP_CONFIG['sso_url']}"
    AssertionConsumerServiceURL="{SP_CONFIG['acs_url']}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{SP_CONFIG['entity_id']}</saml:Issuer>
    <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
    <samlp:RequestedAuthnContext Comparison="exact">
        <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
    </samlp:RequestedAuthnContext>
</samlp:AuthnRequest>'''
    
    return authn_request, request_id


