@app.route('/saml/login')
def saml_login():
    """Initiate SAML login"""
    authn_request, request_id = generate_authn_request()
    session['authn_request_id'] = request_id
    
    # Encode the request
    saml_request = base64.b64encode(authn_request.encode()).decode()
    
    return render_template_string('''
    <!DOCTYPE html>
    <html>
    <head>
        <title>Redirecting to IdP</title>
    </head>
    <body onload="document.forms[0].submit()">
        <form method="post" action="{{ idp_sso_url }}">
            <input type="hidden" name="SAMLRequest" value="{{ saml_request }}" />
            <input type="hidden" name="RelayState" value="{{ relay_state }}" />
            <noscript>
                <p>JavaScript is disabled. Click the button to continue.</p>
                <input type="submit" value="Continue" />
            </noscript>
        </form>
    </body>
    </html>
    ''', idp_sso_url=IDP_CONFIG['sso_url'], saml_request=saml_request, relay_state='/')


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """Assertion Consumer Service - processes SAML responses"""
    saml_response = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', '/')
    
    if not saml_response:
        return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head><title>Error</title></head>
        <body>
            <h1>Error</h1>
            <p>No SAML response received</p>
            <a href="/">Return to home</a>
        </body>
        </html>
        '''), 400
    
    # Parse SAML response
    assertion, error = parse_saml_response(saml_response)
    
    if error:
        return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head>
            <title>Authentication Error</title>
            <style>
                body { font-family: Arial, sans-serif; margin: 40px; }
                .error { background: #f8d7da; color: #721c24; padding: 20px; 
                        border-radius: 5px; border: 1px solid #f5c6cb; }
            </style>
        </head>
        <body>
            <div class="error">
                <h1>Authentication Error</h1>
                <p>{{ error }}</p>
            </div>
            <a href="/">Return to home</a>
        </body>
        </html>
        ''', error=error), 400
    
    # Validate assertion
    is_valid, validation_errors = validate_assertion(assertion)
    
    if not is_valid:
        error_msg = '<br>'.join(validation_errors)
        return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head>
            <title>Validation Error</title>
            <style>
                body { font-family: Arial, sans-serif; margin: 40px; }
                .error { background: #f8d7da; color: #721c24; padding: 20px; 
                        border-radius: 5px; border: 1px solid #f5c6cb; }
            </style>
        </head>
        <body>
            <div class="error">
                <h1>Assertion Validation Failed</h1>
                <p>{{ error_msg|safe }}</p>
            </div>
            <a href="/">Return to home</a>
        </body>
        </html>
        ''', error_msg=error_msg), 400
    
    # Extract user attributes
    user_data = extract_user_attributes(assertion)
    
    # Create user session
    create_user_session(user_data)
    
    return redirect(relay_state)


